sections.example:
vector<int> nums = {3, 1, 4, 1, 5};

// Read-only iteration
for (int x : nums) {
    cout << x << " ";
}
// Output: 3 1 4 1 5

// Modify in place
for (int& x : nums) {
    x *= 2;
}
// nums is now {6, 2, 8, 2, 10}

